        }
        for ($i = 0; $i < count($rawTrades); $i++) {
            $trade = $this->parse_trade($rawTrades[$i]);
            $symbol = $this->safe_string($trade, 'symbol');
            $symbols[$symbol] = true;
            $stored->append ($trade);
        }
        $keys = is_array($symbols) ? array_keys($symbols) : array();
        for ($i = 0; $i < count($keys); $i++) {
