    public function watch_positions(?array $symbols = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbols, $since, $limit, $params) {
            /**
             * watches information on multiple $positions
             *
             * @see https://api.docs.extended.exchange/#account-updates-stream
             *
             * @param {string[]} [$symbols] unified market $symbols
             * @param {int} [$since] the earliest time in ms to fetch $positions for
             * @param {int} [$limit] the maximum number of position structures to retrieve
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of ~@link https://docs.ccxt.com/#/?id=position-structure position structures~
             */
            Async\await($this->load_markets());
            $symbols = $this->market_symbols($symbols);
            $messageHash = 'positions';
            if ($symbols !== null) {
                $messageHash .= '::' . implode(',', $symbols);
            }
            $positions = Async\await($this->watch_private($messageHash, array(
                'symbols' => $symbols,
                'limit' => $limit,
            )));
            if ($this->newUpdates) {
                return $positions;
            }
            return $this->filter_by_symbols_since_limit($this->positions, $symbols, $since, $limit, true);
        }) ();
    }

    public function handle_positions(Client $client, $message) {
        //
        //     {
        //         "type" => "POSITION",
        //         "data" => {
        //             "positions" => array(
        //                 array(
        //                     "id" => 1,
        //                     "accountId" => 1,
        //                     "market" => "BTC-USD",
        //                     "side" => "LONG",
        //                     "leverage" => "10",
        //                     "size" => "0.1",
        //                     "value" => "4000",
        //                     "openPrice" => "39000",
        //                     "markPrice" => "40000",
        //                     "updatedAt" => 1701563440000
        //                 }
        //             )
        //         ),
        //         "ts" => 1715886400000,
        //         "seq" => 1
        //     }
        //
        if ($this->positions === null) {
            $this->positions = new ArrayCacheBySymbolBySide ();
        }
        $stored = $this->positions;
        $data = $this->safe_dict($message, 'data', array());
        $rawPositions = $this->safe_list($data, 'positions', array());
        $newPositions = array();
        $first = $this->safe_dict($rawPositions, 0);
        if ($first === null) {
            return;
        }
        for ($i = 0; $i < count($rawPositions); $i++) {
            $rawPosition = $rawPositions[$i];
            $marketId = $this->safe_string($rawPosition, 'market');
            if ($marketId === null) {
                continue;
            }
            $position = $this->parse_position($rawPosition);
            $newPositions[] = $position;
            $stored->append ($position);
        }
        $messageHashes = $this->find_message_hashes($client, 'positions::');
        for ($i = 0; $i < count($messageHashes); $i++) {
            $messageHash = $messageHashes[$i];
            $parts = explode('::', $messageHash);
            $symbolsString = $parts[1];
            $symbols = explode(',', $symbolsString);
            $filtered = $this->filter_by_array($newPositions, 'symbol', $symbols, false);
            if (!$this->is_empty($filtered)) {
                $client->resolve ($filtered, $messageHash);
            }
        }
        $client->resolve ($newPositions, 'positions');
    }

