    public function parse_ws_funding_rate($fundingRate, $market = null, $message = null): array {
        $marketId = $this->safe_string($fundingRate, 'm');
        $market = $this->safe_market($marketId, $market);
        $timestamp = $this->safe_integer($message, 'ts');
        $fundingTimestamp = $this->safe_integer($fundingRate, 'T');
        return array(
            'info' => $fundingRate,
            'symbol' => $market['symbol'],
            'markPrice' => null,
            'indexPrice' => null,
            'interestRate' => null,
            'estimatedSettlePrice' => null,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'fundingRate' => $this->safe_number($fundingRate, 'f'),
            'fundingTimestamp' => $fundingTimestamp,
            'fundingDatetime' => $this->iso8601($fundingTimestamp),
            'nextFundingRate' => null,
            'nextFundingTimestamp' => null,
            'nextFundingDatetime' => null,
            'previousFundingRate' => null,
            'previousFundingTimestamp' => null,
            'previousFundingDatetime' => null,
            'interval' => null,
        );
    }

